VALUES
  ('public-health-specialist-moex-00757', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列何者非屬地方主管機關對於傳染病發生時採行措施之權限？', '["停止辦理婚宴", "管制搭乘交通工具", "要求撤離特定場所", "調整病例通報時限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00758', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '長輩圈流行以Line傳早安圖，並分享重要防疫衛教及訊息。王爸爸是退休教師，早上參加衛 生局志工聯誼活動，有志工傳訊「早安！緊急通知OO市場已傳多起傳染病確診，切勿靠近」， 他考慮分享其他退休老師群組。如您是他公衛系畢業的小孩，要如何幫忙分析提供法律意見？', '["可積極轉傳，因為知悉而未轉傳導致傳染於他人之虞者，依嚴重特殊傳染性肺炎防治及紓 困振興特別條例，處2年以下有期徒刑、拘役或新臺幣20萬元以上200萬元以下罰金", "依照傳染病防治法第64條第4款，洩漏因業務知悉傳染病人有關資料，處新臺幣9萬元以 上45萬元以下罰鍰", "依傳染病防治法第63條屬散播傳染病流行疫情之謠言，足生損害於公眾或他人者，科新臺 幣300萬元以下罰金", "依嚴重特殊傳染性肺炎防治及紓困振興特別條例第14條，散播傳染病流行疫情之謠言，足 生損害於公眾或他人者，可處1年以下有期徒刑且併科新臺幣300萬元以下罰金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00759', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', 'COVID-19於2020年開始，對於臺灣及國際產生巨大的影響，關於COVID-19疫情相關措施 下列何者正確？', '["在我國的正式名稱為「嚴重特殊傳染性肺炎」，其為傳染病防治法之新興傳染病，衛生福利 部疾病管制署將其與嚴重急性呼吸道症候群（SARS）同列為第一類傳染病", "為防治COVID-19，個人防護裝備（PPE）極為重要，疫情之初，指揮中心徵用醫用口罩， 依傳染病防治法第54條公告其為防疫物資", "傳染病防治法第74條規定，因執行第五類傳染病防治工作致傷病或死亡者，主管機關得酌 予補助，此為嚴重特殊傳染性肺炎防治及紓困振興特別條例之法源", "依照現行規定，醫師診治病人發現有COVID-19病人，因其為第一類法定傳染病，需於24 小時之內通報衛生主管機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00760', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '有關精神疾病強制住院，由中央主管機關設置精神疾病強制鑑定、強制社區治療審查會，並 由該會進行審查，關於審查會應包含之成員，不包括下列何者？', '["物理治療師", "病人權益促進團體代表", "法律專家及其他專業人士", "社會工作師"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00761', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '依據我國菸害防制法的相關規定，下列何者之場所除吸菸區外，不得吸菸；未設吸菸區者， 全面禁止吸菸？', '["大專校院、圖書館、博物館、美術館及其他文化或社會教育機構所在之室外場所", "政府機關及公營事業機構所在之室內場所", "大眾運輸工具、計程車、遊覽車、捷運系統、車站及旅客等候室", "金融機構、郵局及電信事業之營業場所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00762', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '依照病人自主權利法第14條第1項規定，下列何種臨床狀況及執行內容，沒有違法之虞？', '["失智病人，前有預立醫療決定，醫院依其預立醫療決定終止維持生命治療", "處於暫時之植物人狀態，前有預立醫療決定，醫院依其預立醫療決定撤除維持生命治療", "前已有預立醫療決定之病人，處於昏迷狀況已多日，家屬已放棄希望，醫院依其預立醫療 決定不再施行維持生命治療", "末期病人已無法進食，前有預立醫療決定，醫師依其預立醫療決定撤除其全部流體餵養， 惟家屬擔心末期病人餓死"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00763', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '代理孕母與胎兒出生後的親子權利，下列那一個倫理原則的道德規範最強烈？', '["出資者與代理孕母之間的民事契約內容", "依據民法中有關親屬定義內容，否認此定義可能引發的廣泛社會面影響", "孕婦與胎兒之間的情感連結會因為懷孕期限而被強迫割捨", "孕婦與胎兒之間的情感連結無法事前預測所產生的訊息不對稱性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00764', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '依據藥師法第19條之規定，下列何者不屬於藥劑包裝上應記明事項？', '["病人年齡", "藥品作用或適應症", "警語或副作用", "藥局地點、名稱及調劑者姓名"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00765', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '有關全民健康保險資料庫可否作為匿名研究用途的爭議，其爭議來源主要來自那一個法律上 的規範？', '["全民健康保險法第79條（有關健保資料的保存與利用）", "個人資料保護法第3條（有關個人資料的法律保留權利）", "個人資料保護法第5條（有關個人資料蒐集目的與正當性）", "個人資料保護法第6條（有關醫療資料之利用規範）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00766', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列有關生命權、身體健康權之敘述，何者錯誤？', '["生命權與身體健康權的保護主體僅係自然人，惟其權利保護先考量該人之心智或精神狀況 有所不同", "免於身心健康之身體權，非憲法第8條明文列舉之自由權利，惟基於人性尊嚴理念，亦屬 憲法第22條之基本權利", "人民身體之生存權，惟憲法第15條明定，生存權為生命保障之依據，墮胎或自殺涉及「生 命權」", "身體健康權，包含身體健康的自主決定權，耶和華見證人拒絕輸血的行為，涉及身體健康 權或人格權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
